            _services.AddSingleton<SubscriptionApiEvents>();
            _services.AddSingleton<TokenVaultApiEvents>();
            _services.AddSingleton<UtilitiesApiEvents>();
        }

        /// <summary>
        /// Configures the HttpClients.
        /// </summary>
        /// <param name="client"></param>
        /// <param name="builder"></param>
        /// <returns></returns>
        public HostConfiguration AddApiHttpClients
        (
            Action<HttpClient>? client = null, Action<IHttpClientBuilder>? builder = null)
        {
            if (client == null)
                client = c => c.BaseAddress = new Uri(ClientUtils.BASE_ADDRESS);

            List<IHttpClientBuilder> builders = new List<IHttpClientBuilder>();

            builders.Add(_services.AddHttpClient<ICustomersApi, CustomersApi>(client));
            builders.Add(_services.AddHttpClient<IDisputesApi, DisputesApi>(client));
            builders.Add(_services.AddHttpClient<IDowntimeApi, DowntimeApi>(client));
            builders.Add(_services.AddHttpClient<IEasySplitApi, EasySplitApi>(client));
            builders.Add(_services.AddHttpClient<IEligibilityApi, EligibilityApi>(client));
            builders.Add(_services.AddHttpClient<IIntellisenseApi, IntellisenseApi>(client));
            builders.Add(_services.AddHttpClient<IOffersApi, OffersApi>(client));
            builders.Add(_services.AddHttpClient<IOrdersApi, OrdersApi>(client));
            builders.Add(_services.AddHttpClient<IPGReconciliationApi, PGReconciliationApi>(client));
            builders.Add(_services.AddHttpClient<IPaymentLinksApi, PaymentLinksApi>(client));
            builders.Add(_services.AddHttpClient<IPaymentsApi, PaymentsApi>(client));
            builders.Add(_services.AddHttpClient<IReconciliationApi, ReconciliationApi>(client));
            builders.Add(_services.AddHttpClient<IRefundsApi, RefundsApi>(client));
            builders.Add(_services.AddHttpClient<ISettlementReconciliationApi, SettlementReconciliationApi>(client));
            builders.Add(_services.AddHttpClient<ISettlementsApi, SettlementsApi>(client));
            builders.Add(_services.AddHttpClient<ISimulationApi, SimulationApi>(client));
            builders.Add(_services.AddHttpClient<ISoftPOSApi, SoftPOSApi>(client));
            builders.Add(_services.AddHttpClient<ISubscriptionApi, SubscriptionApi>(client));
            builders.Add(_services.AddHttpClient<ITokenVaultApi, TokenVaultApi>(client));
            builders.Add(_services.AddHttpClient<IUtilitiesApi, UtilitiesApi>(client));
            
            if (builder != null)
                foreach (IHttpClientBuilder instance in builders)
                    builder(instance);

            HttpClientsAdded = true;

            return this;
        }

        /// <summary>
        /// Configures the JsonSerializerSettings
        /// </summary>
        /// <param name="options"></param>
        /// <returns></returns>
        public HostConfiguration ConfigureJsonOptions(Action<JsonSerializerOptions> options)
        {
            options(_jsonOptions);

            return this;
        }

        /// <summary>
        /// Adds tokens to your IServiceCollection
        /// </summary>
        /// <typeparam name="TTokenBase"></typeparam>
        /// <param name="token"></param>
        /// <returns></returns>
        public HostConfiguration AddTokens<TTokenBase>(TTokenBase token) where TTokenBase : TokenBase
        {
            return AddTokens(new TTokenBase[]{ token });
        }

        /// <summary>
        /// Adds tokens to your IServiceCollection
        /// </summary>
        /// <typeparam name="TTokenBase"></typeparam>
        /// <param name="tokens"></param>
        /// <returns></returns>
        public HostConfiguration AddTokens<TTokenBase>(IEnumerable<TTokenBase> tokens) where TTokenBase : TokenBase
        {
            TokenContainer<TTokenBase> container = new TokenContainer<TTokenBase>(tokens);
            _services.AddSingleton(services => container);

            return this;
        }

        /// <summary>
        /// Adds a token provider to your IServiceCollection
        /// </summary>
        /// <typeparam name="TTokenProvider"></typeparam>
        /// <typeparam name="TTokenBase"></typeparam>
        /// <returns></returns>
        public HostConfiguration UseProvider<TTokenProvider, TTokenBase>() 
            where TTokenProvider : TokenProvider<TTokenBase>
            where TTokenBase : TokenBase
        {
            _services.AddSingleton<TTokenProvider>();
            _services.AddSingleton<TokenProvider<TTokenBase>>(services => services.GetRequiredService<TTokenProvider>());

            return this;
        }
    }
}
